      (options, requester) =>
        (requester || clientRequester)({
          maxRedirects: 0,
          maxRetries: config.maxRetries,
          retryDelay: config.retryDelay,
          lineage: config.lineage,
          ...options,
        } as Any),
      config,
    )
  }

  return {requester: defaultRequester, createClient}
